import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Driver {
  id: string;
  name: string;
  team: string;
  number: number;
  points: number;
  image: string;
  countryCode: string;
}

export interface NewsItem {
  id: string;
  title: string;
  summary: string;
  timestamp: string;
  category: 'Breaking' | 'Tech' | 'Interview' | 'Rumor';
  imageUrl: string;
}

export interface LiveUpdate {
  lap: number;
  message: string;
  flag: 'GREEN' | 'YELLOW' | 'RED' | 'SC' | 'VSC' | 'CHEQUERED';
  timestamp: number;
}

export enum ViewState {
  HOME = 'HOME',
  NEWS = 'NEWS',
  DRIVERS = 'DRIVERS',
  STREAMS = 'STREAMS'
}

export interface RaceSession {
  name: string;
  track: string;
  status: 'LIVE' | 'UPCOMING' | 'FINISHED';
  currentLap?: number;
  totalLaps?: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { NewsItem, LiveUpdate, Driver } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Models
const FAST_MODEL = 'gemini-3-flash-preview';

/**
 * Generates simulated live race commentary based on a scenario.
 */
export const generateLiveCommentary = async (raceName: string, currentLap: number, totalLaps: number): Promise<LiveUpdate> => {
  try {
    const prompt = `
      You are a Formula 1 live commentator. Generate a SHORT, DRAMATIC single-sentence update for the ${raceName}.
      Current Lap: ${currentLap}/${totalLaps}.
      Context: Provide a realistic race event (overtake, pit stop, crash, fastest lap, or gap update).
      Return JSON only.
    `;

    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            message: { type: Type.STRING, description: "The commentary text in Russian language." },
            flag: { type: Type.STRING, enum: ['GREEN', 'YELLOW', 'RED', 'SC', 'VSC', 'CHEQUERED'] }
          },
          required: ['message', 'flag']
        }
      }
    });

    const data = JSON.parse(response.text || '{}');

    return {
      lap: currentLap,
      timestamp: Date.now(),
      message: data.message || "Гонка продолжается в спокойном режиме.",
      flag: data.flag || 'GREEN'
    };
  } catch (error) {
    console.error("Gemini Live Error:", error);
    return {
      lap: currentLap,
      timestamp: Date.now(),
      message: "Связь с трассой восстанавливается...",
      flag: 'GREEN'
    };
  }
};

/**
 * Generates latest F1 news headlines.
 */
export const generateNews = async (): Promise<NewsItem[]> => {
  try {
    const prompt = `
      Generate 4 fictional but realistic Formula 1 news headlines and summaries for the current season.
      Mix of topics: Technical updates, Driver market rumors, Race analysis.
      Language: Russian.
      Return JSON array.
    `;

    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              summary: { type: Type.STRING },
              category: { type: Type.STRING, enum: ['Breaking', 'Tech', 'Interview', 'Rumor'] }
            },
            required: ['title', 'summary', 'category']
          }
        }
      }
    });

    const data = JSON.parse(response.text || '[]');

    return data.map((item: any, index: number) => ({
      id: `news-${index}-${Date.now()}`,
      title: item.title,
      summary: item.summary,
      timestamp: new Date().toISOString(),
      category: item.category,
      imageUrl: `https://picsum.photos/800/600?random=${index + 10}`
    }));
  } catch (error) {
    console.error("Gemini News Error:", error);
    return [];
  }
};

/**
 * Simulates driver analysis or fun fact.
 */
export const getDriverInsight = async (driverName: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: FAST_MODEL,
            contents: `Give me a one sentence interesting technical or driving style fact about F1 driver ${driverName} in Russian.`,
        });
        return response.text || "Информация недоступна.";
    } catch (e) {
        return "Гонщик высшего класса.";
    }
}

import React from 'react';
import { ViewState } from '../types';
import { Home, Newspaper, Users, Tv } from 'lucide-react';

interface NavigationProps {
  currentView: ViewState;
  setView: (view: ViewState) => void;
}

export const Navigation: React.FC<NavigationProps> = ({ currentView, setView }) => {
  const navItems = [
    { view: ViewState.HOME, icon: Home, label: 'Гонка' },
    { view: ViewState.NEWS, icon: Newspaper, label: 'Новости' },
    { view: ViewState.DRIVERS, icon: Users, label: 'Пилоты' },
    { view: ViewState.STREAMS, icon: Tv, label: 'Эфир' },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 pb-safe">
      <div className="glass-panel mx-4 mb-4 rounded-2xl flex justify-between items-center px-6 py-4 shadow-2xl shadow-f1-red/10">
        {navItems.map((item) => {
            const isActive = currentView === item.view;
            return (
                <button
                    key={item.view}
                    onClick={() => setView(item.view)}
                    className={`flex flex-col items-center gap-1 transition-all duration-300 ${isActive ? 'text-f1-red scale-110' : 'text-gray-400 hover:text-white'}`}
                >
                    <item.icon size={24} strokeWidth={isActive ? 2.5 : 2} />
                    <span className="text-[10px] font-medium tracking-wide uppercase">{item.label}</span>
                </button>
            );
        })}
      </div>
    </nav>
  );
};

import React, { useState } from 'react';
import { Driver } from '../types';
import { getDriverInsight } from '../services/geminiService';
import { ChevronRight, Zap } from 'lucide-react';

interface DriverCardProps {
  driver: Driver;
}

export const DriverCard: React.FC<DriverCardProps> = ({ driver }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleAnalyze = async () => {
    if (insight) return;
    setLoading(true);
    const text = await getDriverInsight(driver.name);
    setInsight(text);
    setLoading(false);
  };

  return (
    <div className="glass-panel rounded-2xl overflow-hidden relative group">
      <div className="absolute top-0 right-0 p-4 opacity-10 font-display text-6xl font-black italic select-none">
        {driver.number}
      </div>

      <div className="flex items-end p-4 pt-8 gap-4">
        <img 
            src={driver.image} 
            alt={driver.name}
            className="w-24 h-24 rounded-full border-2 border-f1-red object-cover bg-gray-800"
        />
        <div className="flex-1 pb-2">
            <h3 className="text-xl font-bold leading-none">{driver.name}</h3>
            <p className="text-f1-red text-sm font-semibold uppercase tracking-wider">{driver.team}</p>
        </div>
      </div>

      <div className="px-4 pb-4">
        <div className="flex justify-between items-center bg-white/5 rounded-lg p-3 mb-3">
             <span className="text-gray-400 text-xs uppercase">Очки сезона</span>
             <span className="text-xl font-display font-bold text-white">{driver.points}</span>
        </div>

        {insight ? (
            <div className="text-xs text-gray-300 bg-f1-red/10 p-3 rounded-lg border border-f1-red/20 animate-fade-in">
                <Zap size={12} className="inline mr-1 text-f1-red" />
                {insight}
            </div>
        ) : (
            <button 
                onClick={handleAnalyze}
                disabled={loading}
                className="w-full text-xs font-bold uppercase tracking-wider py-3 rounded-lg bg-white/10 hover:bg-f1-red hover:text-white transition-colors flex items-center justify-center gap-2"
            >
                {loading ? 'Анализ...' : 'Анализ стиля AI'}
                {!loading && <ChevronRight size={14} />}
            </button>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { generateLiveCommentary } from '../services/geminiService';
import { LiveUpdate, RaceSession } from '../types';
import { Flag, Activity, Timer, MapPin } from 'lucide-react';

export const LiveRace: React.FC = () => {
  const [session] = useState<RaceSession>({
    name: "Гран-при Монако",
    track: "Circuit de Monaco",
    status: 'LIVE',
    currentLap: 45,
    totalLaps: 78
  });
  const [updates, setUpdates] = useState<LiveUpdate[]>([]);
  const [currentLap, setCurrentLap] = useState(session.currentLap || 1);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Simulate lap progression and Gemini commentary
  useEffect(() => {
    let intervalId: NodeJS.Timeout;

    const fetchUpdate = async () => {
      if (currentLap >= (session.totalLaps || 78)) return;

      // Simulate lap increment
      setCurrentLap(prev => Math.min(prev + 1, session.totalLaps || 78));

      const update = await generateLiveCommentary(session.name, currentLap, session.totalLaps || 78);
      setUpdates(prev => [...prev, update]);
    };

    // Initial fetch
    fetchUpdate();

    // Loop
    intervalId = setInterval(fetchUpdate, 8000); // New update every 8 seconds for demo

    return () => clearInterval(intervalId);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentLap]);

  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [updates]);

  return (
    <div className="flex flex-col h-full pt-4 pb-24 px-4 space-y-4">

      {/* Header Stat Card */}
      <div className="glass-panel p-6 rounded-3xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-f1-red/20 blur-3xl -mr-10 -mt-10 rounded-full"></div>

        <div className="flex justify-between items-start mb-4">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    <span className="animate-pulse w-2 h-2 bg-f1-red rounded-full"></span>
                    <span className="text-f1-red font-bold text-xs tracking-widest uppercase">Live Session</span>
                </div>
                <h1 className="text-2xl font-display font-bold">{session.name}</h1>
                <p className="text-gray-400 text-sm flex items-center gap-1"><MapPin size={12}/> {session.track}</p>
            </div>
            <div className="text-right">
                <span className="block text-4xl font-display font-black italic">{currentLap}<span className="text-lg text-gray-500 not-italic">/{session.totalLaps}</span></span>
                <span className="text-xs text-gray-400 uppercase tracking-widest">Круг</span>
            </div>
        </div>

        {/* Telemetry Mockup */}
        <div className="grid grid-cols-3 gap-2 mt-4">
            <div className="bg-black/40 p-2 rounded-lg text-center">
                <span className="block text-xs text-gray-500 uppercase">Лидер</span>
                <span className="font-bold text-sm">VER</span>
            </div>
            <div className="bg-black/40 p-2 rounded-lg text-center border border-f1-red/30">
                <span className="block text-xs text-gray-500 uppercase">Gap</span>
                <span className="font-bold text-sm text-f1-red">+1.245s</span>
            </div>
             <div className="bg-black/40 p-2 rounded-lg text-center">
                <span className="block text-xs text-gray-500 uppercase">Шины</span>
                <span className="font-bold text-sm text-yellow-500">MED</span>
            </div>
        </div>
      </div>

      {/* Live Feed */}
      <div className="flex-1 glass-panel rounded-3xl p-1 overflow-hidden flex flex-col">
        <div className="p-4 border-b border-white/5 flex justify-between items-center bg-black/20">
            <h2 className="font-display text-sm font-bold uppercase tracking-wider flex items-center gap-2">
                <Activity size={16} className="text-f1-red"/>
                Трансляция
            </h2>
            <div className="flex gap-2">
                 <span className="w-1.5 h-6 bg-green-500 -skew-x-12 rounded-sm"></span>
                 <span className="w-1.5 h-6 bg-green-500 -skew-x-12 rounded-sm"></span>
            </div>
        </div>

        <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto p-4 space-y-4 scroll-smooth"
        >
            {updates.length === 0 && (
                <div className="text-center text-gray-500 py-10 animate-pulse">
                    Получение телеметрии...
                </div>
            )}
            {updates.map((update, idx) => (
                <div key={idx} className="flex gap-4 animate-fade-in-up">
                    <div className="flex flex-col items-center min-w-[3rem]">
                        <span className="text-xs font-mono text-gray-500 mb-1">{update.lap}</span>
                        {update.flag === 'GREEN' && <Flag size={16} className="text-green-500" fill="currentColor"/>}
                        {update.flag === 'YELLOW' && <Flag size={16} className="text-yellow-500" fill="currentColor"/>}
                        {update.flag === 'RED' && <Flag size={16} className="text-red-500" fill="currentColor"/>}
                        {update.flag === 'CHEQUERED' && <Flag size={16} className="text-white" fill="currentColor"/>}
                        {(update.flag === 'SC' || update.flag === 'VSC') && <div className="text-[10px] font-bold bg-yellow-500 text-black px-1 rounded">SC</div>}
                    </div>
                    <div className="flex-1 pb-4 border-b border-white/5">
                        <p className="text-sm leading-relaxed text-gray-200">{update.message}</p>
                        <span className="text-[10px] text-gray-600 mt-2 block">{new Date(update.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second:'2-digit'})}</span>
                    </div>
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

