                    </div>
                ))
            )}
          </div>
        );
      case ViewState.DRIVERS:
        return (
          <div className="pt-20 pb-24 px-4">
             <h1 className="text-3xl font-display font-bold mb-6 px-2">Пилоты <span className="text-f1-red">2024</span></h1>
