                 {STREAMS.map(stream => (
                     <div key={stream.id} className="glass-panel p-4 rounded-xl flex items-center justify-between hover:bg-white/5 transition-colors cursor-pointer group">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-full bg-white/10 flex items-center justify-center text-f1-red group-hover:bg-f1-red group-hover:text-white transition-colors">
                                <Play fill="currentColor" size={20} className="ml-1"/>
                            </div>
                            <div>
                                <h3 className="font-bold">{stream.title}</h3>
                                <div className="flex gap-2 text-xs text-gray-400 mt-1">
                                    <span className="flex items-center gap-1"><span className="w-1.5 h-1.5 bg-red-500 rounded-full animate-pulse"></span> {stream.viewerCount}</span>
                                    <span className="border border-white/20 px-1 rounded text-[10px]">{stream.quality}</span>
                                </div>
                            </div>
                        </div>
                        <div className="text-gray-500 group-hover:text-white">
