                 <div className="mt-8 p-4 bg-f1-red/10 border border-f1-red/20 rounded-xl">
                    <h4 className="font-bold text-f1-red mb-2 text-sm uppercase">Важное уведомление</h4>
                    <p className="text-xs text-gray-300">Трансляции предоставляются сторонними сервисами. Paddock Prime не несет ответственности за контент.</p>
                 </div>
            </div>
          );
      default:
        return null;
    }
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans selection:bg-f1-red selection:text-white">
      {/* Top Bar */}
      <header className="fixed top-0 w-full z-40 bg-black/80 backdrop-blur-md border-b border-white/5 h-16 flex items-center justify-between px-4">
        <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-f1-red rounded-lg flex items-center justify-center transform -skew-x-12">
                <span className="font-display font-black text-white text-lg skew-x-12">F1</span>
            </div>
            <span className="font-display font-bold tracking-tight text-lg">PADDOCK<span className="text-f1-red">PRIME</span></span>
        </div>
        <div className="flex gap-4">
            <button className="text-gray-400 hover:text-white"><Search size={20}/></button>
            <button className="text-gray-400 hover:text-white relative">
                <Bell size={20}/>
                <span className="absolute -top-1 -right-1 w-2 h-2 bg-f1-red rounded-full"></span>
            </button>
        </div>
      </header>

      <main className="max-w-md mx-auto min-h-screen relative bg-gradient-to-b from-f1-dark to-black">
        {renderContent()}
      </main>

      <Navigation currentView={currentView} setView={setView} />
    </div>
  );
}

