import { GoogleGenAI, Type } from "@google/genai";
import { NewsItem, LiveUpdate, Driver } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Models
const FAST_MODEL = 'gemini-3-flash-preview';

/**
 * Generates simulated live race commentary based on a scenario.
 */
export const generateLiveCommentary = async (raceName: string, currentLap: number, totalLaps: number): Promise<LiveUpdate> => {
  try {
    const prompt = `
      You are a Formula 1 live commentator. The date is February 16, 2026.
      Event: ${raceName} (2026 Season).
      Context: This is the start of the new 2026 Regulatory Era (Active Aero, New Power Units).
      Current Status: Lap/Loop ${currentLap}.
      Generate a SHORT, DRAMATIC single-sentence update in Russian.
      Topics: Active aero wing adjustments, new engine sounds, porpoising checks, lap times, red flags for reliability issues.
      Return JSON only.
    `;

    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            message: { type: Type.STRING, description: "The commentary text in Russian language." },
            flag: { type: Type.STRING, enum: ['GREEN', 'YELLOW', 'RED', 'SC', 'VSC', 'CHEQUERED'] }
          },
          required: ['message', 'flag']
        }
      }
    });

    const data = JSON.parse(response.text || '{}');

    return {
      lap: currentLap,
      timestamp: Date.now(),
      message: data.message || "Тесты продолжаются, команды собирают данные.",
      flag: data.flag || 'GREEN'
    };
  } catch (error) {
    console.error("Gemini Live Error:", error);
    return {
      lap: currentLap,
      timestamp: Date.now(),
      message: "Связь с паддоком восстанавливается...",
      flag: 'GREEN'
    };
  }
};

/**
 * Generates latest F1 news headlines for Feb 2026.
 */
export const generateNews = async (): Promise<NewsItem[]> => {
  try {
    const prompt = `
      Current Date: February 16, 2026.
      Generate 4 realistic Formula 1 news headlines and summaries.
      Context: Pre-season testing in Bahrain, New 2026 Regulations (Active Aero, Sustainable Fuels).
      Key storylines: 
      - Lewis Hamilton's first season at Ferrari.
      - Andrea Kimi Antonelli's debut at Mercedes.
      - Adrian Newey's impact at Aston Martin.
      - Audi's first full season entering F1.
      Language: Russian.
      Return JSON array.
    `;

    const response = await ai.models.generateContent({
      model: FAST_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              summary: { type: Type.STRING },
              category: { type: Type.STRING, enum: ['Breaking', 'Tech', 'Interview', 'Rumor'] }
            },
            required: ['title', 'summary', 'category']
          }
        }
      }
    });

    const data = JSON.parse(response.text || '[]');

    return data.map((item: any, index: number) => ({
      id: `news-${index}-${Date.now()}`,
      title: item.title,
      summary: item.summary,
      timestamp: new Date().toISOString(),
      category: item.category,
      imageUrl: `https://picsum.photos/800/600?random=${index + 20}`
    }));
  } catch (error) {
    console.error("Gemini News Error:", error);
    return [];
  }
};

/**
 * Simulates driver analysis or fun fact.
 */
export const getDriverInsight = async (driverName: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: FAST_MODEL,
            contents: `The year is 2026. Give me a one sentence interesting fact about F1 driver ${driverName}'s prospects for the 2026 season in Russian.`,
        });
        return response.text || "Информация недоступна.";
    } catch (e) {
        return "Гонщик готов к сезону 2026.";
    }
}

