import React, { useEffect, useState, useRef } from 'react';
import { generateLiveCommentary } from '../services/geminiService';
import { LiveUpdate, RaceSession } from '../types';
import { Flag, Activity, Timer, MapPin } from 'lucide-react';

export const LiveRace: React.FC = () => {
  const [session] = useState<RaceSession>({
    name: "Bahrain Pre-Season Testing",
    track: "Bahrain International Circuit",
    status: 'LIVE',
    currentLap: 24, // Starting lap
    totalLaps: 100 // Target laps
  });

  const [updates, setUpdates] = useState<LiveUpdate[]>([]);
  const [currentLap, setCurrentLap] = useState(session.currentLap || 1);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Simulate lap progression and Gemini commentary
  useEffect(() => {
    let intervalId: ReturnType<typeof setInterval>;

    const fetchUpdate = async () => {
      // Check lap limit
      if (currentLap >= (session.totalLaps || 100)) {
          return; 
      }

      // Generate content
      const update = await generateLiveCommentary(session.name, currentLap, session.totalLaps || 100);
      setUpdates(prev => [...prev, update]);

      // Increment Lap ONLY after update
      setCurrentLap(prev => {
          const next = prev + 1;
          return next > (session.totalLaps || 100) ? prev : next;
      });
    };

    // Initial fetch
    if (updates.length === 0) fetchUpdate();

