            <div>
                <div className="flex items-center gap-2 mb-1">
                    <span className="animate-pulse w-2 h-2 bg-f1-red rounded-full"></span>
                    <span className="text-f1-red font-bold text-xs tracking-widest uppercase">Live: Day 1</span>
                </div>
                <h1 className="text-xl md:text-2xl font-display font-bold leading-tight">{session.name}</h1>
                <p className="text-gray-400 text-sm flex items-center gap-1 mt-1"><MapPin size={12}/> {session.track}</p>
            </div>
            <div className="text-right ml-4">
                <span className="block text-4xl font-display font-black italic">{currentLap}</span>
                <span className="text-[10px] text-gray-400 uppercase tracking-widest">/{session.totalLaps}</span>
            </div>
        </div>

        {/* Telemetry Mockup */}
        <div className="grid grid-cols-3 gap-2 mt-4">
            <div className="bg-black/40 p-2 rounded-lg text-center">
                <span className="block text-[10px] text-gray-500 uppercase">Best</span>
                <span className="font-bold text-sm">1:29.432</span>
            </div>
            <div className="bg-black/40 p-2 rounded-lg text-center border border-f1-red/30">
                <span className="block text-[10px] text-gray-500 uppercase">Temp</span>
                <span className="font-bold text-sm text-f1-red">34°C</span>
            </div>
             <div className="bg-black/40 p-2 rounded-lg text-center">
                <span className="block text-[10px] text-gray-500 uppercase">Шины</span>
                <span className="font-bold text-sm text-white">C3</span>
            </div>
        </div>
      </div>

      {/* Live Feed */}
      <div className="flex-1 glass-panel rounded-3xl p-1 overflow-hidden flex flex-col min-h-0">
        <div className="p-3 border-b border-white/5 flex justify-between items-center bg-black/20 shrink-0">
            <h2 className="font-display text-xs font-bold uppercase tracking-wider flex items-center gap-2">
                <Activity size={14} className="text-f1-red"/>
                Лента
            </h2>
            <div className="flex gap-1">
                 <span className="w-1 h-4 bg-green-500 -skew-x-12 rounded-[1px]"></span>
                 <span className="w-1 h-4 bg-green-500 -skew-x-12 rounded-[1px]"></span>
            </div>
        </div>

        <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto p-4 space-y-4 scroll-smooth"
        >
            {updates.length === 0 && (
                <div className="flex flex-col items-center justify-center h-full text-gray-500 gap-2">
                    <div className="w-6 h-6 border-2 border-f1-red border-t-transparent rounded-full animate-spin"></div>
                    <span className="text-xs">Синхронизация...</span>
                </div>
            )}
            {updates.map((update, idx) => (
                <div key={idx} className="flex gap-4 animate-fade-in-up">
                    <div className="flex flex-col items-center min-w-[3rem] pt-1">
                        <span className="text-[10px] font-mono text-gray-500 mb-1">{new Date(update.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                        {update.flag === 'GREEN' && <Flag size={14} className="text-green-500" fill="currentColor"/>}
                        {update.flag === 'YELLOW' && <Flag size={14} className="text-yellow-500" fill="currentColor"/>}
